{"type": "function", "name": "get_all_tweets", "description": "Retrieve all tweet objects from the tweets.json dataset.", "parameters": {"type": "object", "properties": {}, "required": []}}
{"type": "function", "name": "get_tweet_by_id", "description": "Retrieve a single tweet by its id from tweets.json.", "parameters": {"type": "object", "properties": {"tweet_id": {"type": "string", "description": "The id of the tweet to retrieve."}}, "required": ["tweet_id"]}}
{"type": "function", "name": "get_all_users", "description": "Retrieve all user profile objects from the users.json dataset.", "parameters": {"type": "object", "properties": {}, "required": []}}
{"type": "function", "name": "get_user_by_username", "description": "Retrieve a user profile by its username from users.json.", "parameters": {"type": "object", "properties": {"username": {"type": "string", "description": "The username to look up."}}, "required": ["username"]}}
{"type": "function", "name": "list_following", "description": "Return the list of accounts the user is following from following.json.", "parameters": {"type": "object", "properties": {}, "required": []}}
{"type": "function", "name": "get_following_user_by_username", "description": "Find a followed user by username in following.json.", "parameters": {"type": "object", "properties": {"username": {"type": "string", "description": "Username of the followed account to retrieve."}}, "required": ["username"]}}
{"type": "function", "name": "get_search_results", "description": "Retrieve the list of tweet objects from the search_results.json 'statuses' array.", "parameters": {"type": "object", "properties": {}, "required": []}}
{"type": "function", "name": "search_tweets_in_file", "description": "Search for tweets containing a keyword within the stored search_results.json data.", "parameters": {"type": "object", "properties": {"keyword": {"type": "string", "description": "Keyword to search for inside tweet text."}}, "required": ["keyword"]}}
{"type": "function", "name": "get_post_tweet_response", "description": "Return the full content of post_tweet_response.json, which represents a sample tweet post response.", "parameters": {"type": "object", "properties": {}, "required": []}}
{"type": "function", "name": "get_user_stats", "description": "Retrieve the list of user statistics entries from user_stats.json.", "parameters": {"type": "object", "properties": {}, "required": []}}
{"type": "function", "name": "get_login_status", "description": "Return the current login status record from login_status.json.", "parameters": {"type": "object", "properties": {}, "required": []}}
{"type": "function", "name": "update_login_status", "description": "Update the login_status.json file with a new username and logged_in flag, recording the current UTC time.", "parameters": {"type": "object", "properties": {"username": {"type": "string", "description": "The username to set as currently logged in."}, "logged_in": {"type": "boolean", "description": "True if the user is logged in, False otherwise."}}, "required": ["username", "logged_in"]}}
{"type": "function", "name": "get_all_tweet_comments", "description": "Retrieve all comment (reply) objects from tweet_comments.json.", "parameters": {"type": "object", "properties": {}, "required": []}}
