{"type": "function", "name": "get_metrics_for_tweet", "description": "Retrieve metrics for a specific tweet id from metrics_response.json.", "parameters": {"type": "object", "properties": {"tweet_id": {"type": "string", "description": "The id of the tweet whose metrics should be returned."}}, "required": ["tweet_id"]}}
{"type": "function", "name": "get_user_stats_by_username", "description": "Find a user statistics entry by username from user_stats.json.", "parameters": {"type": "object", "properties": {"username": {"type": "string", "description": "The username to look up in the user statistics file."}}, "required": ["username"]}}
{"type": "function", "name": "create_directory", "description": "Create a new directory or ensure a directory exists. Can create multiple nested directories in one operation.", "parameters": {"type": "object", "properties": {"path": {"type": "string", "description": "Path of the directory to create."}}, "required": ["path"]}}

